import type { Question } from './types'
import { makeQuestionBank } from './base'

type OpenStaxDefinition = {
  id: number
  chapter: string
  source?: string
  title: string
  prompt: string
  correct: string
  wrong: [string, string, string][]
  lesson?: string
}

function isPlaceholderSolution(value?: string) {
  if (!value) return true
  const normalized = value.trim().toLowerCase()
  return normalized === 'see solution' || normalized === 'no solution provided.'
}

function sanitizeOpenStaxDefinitions(definitions: OpenStaxDefinition[]) {
  return definitions.filter((definition) => {
    if (isPlaceholderSolution(definition.correct)) return false
    if (isPlaceholderSolution(definition.lesson)) return false
    if (definition.wrong.some(([label]) => label === 'N/A (Open-ended)')) return false
    return true
  })
}

